use tokio::join;

async fn fetch_user() -> String { "Alice".to_string() }
async fn fetch_orders() -> Vec<String> { vec!["order1".into()] }

#[tokio::main]
async fn main() {
    let (user, orders) = join!(fetch_user(), fetch_orders());
    println!("User: {}, Orders: {:?}", user, orders);
}

use tokio::select;
use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    select! {
        _ = sleep(Duration::from_secs(1)) => println!("timeout"),
        result = async { "data" } => println!("got: {}", result),
    }
}

use tokio::sync::mpsc;

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel(32);

    tokio::spawn(async move {
        tx.send("hello").await.unwrap();
        tx.send("world").await.unwrap();
    });

    while let Some(msg) = rx.recv().await {
        println!("Received: {}", msg);
    }
}

use std::sync::Arc;
use tokio::sync::Mutex;

#[tokio::main]
async fn main() {
    let counter = Arc::new(Mutex::new(0u64));

    let mut handles = vec![];
    for _ in 0..10 {
        let counter = Arc::clone(&counter);
        handles.push(tokio::spawn(async move {
            let mut lock = counter.lock().await;
            *lock += 1;
        }));
    }

    for h in handles { h.await.unwrap(); }
    println!("Counter: {}", *counter.lock().await);
}
